import requests
import json

# 飞书应用凭证
APP_ID = "cli_a929838abb389bc6"
APP_SECRET = "3vasdyspNoUPXCL6TniyLdkQbLqmPqEU"

def get_tenant_token():
    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {"app_id": APP_ID, "app_secret": APP_SECRET}
    response = requests.post(url, json=payload)
    return response.json()["tenant_access_token"] if response.status_code == 200 else None

def send_invite_to_all_group(token):
    """在全员群里发新群邀请"""
    url = "https://open.feishu.cn/open-apis/im/v1/messages"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json; charset=utf-8"
    }
    params = {"receive_id_type": "chat_id"}
    # 全新研发项目工作群
    new_group_id = "oc_deb45ba0f817a83fc9588a36cbc9c7b6"
    group_link = f"https://applink.feishu.cn/client/chat/chatter/{new_group_id}"
    payload = {
        "receive_id": "oc_c74d25c984ead08293cca215d31f00b5",
        "msg_type": "text",
        "content": json.dumps({"text": f"📢 全新【研发项目工作群】已创建完成，请大家点击链接加入：\n{group_link}\n<at user_id=\"ou_5724d98779c961cde9b86d85a614dc3c\">王海</at> <at user_id=\"ou_3415d622ebf35405299c8eea91207c38\">王总</at> 点击即可直接加入，无需审核。"})
    }
    response = requests.post(url, headers=headers, params=params, json=payload)
    if response.status_code == 200 and response.json()["code"] == 0:
        print("✅ 新群邀请已发送到全员群，您和王总点击链接就能直接加入新群，这是完全独立的全新群，和之前的全员群完全分开！")
        print(f"新群ID：{new_group_id}")
        print(f"新群名称：研发项目工作群")
        return True
    else:
        print(f"发送失败：{response.text}")
        return False

if __name__ == "__main__":
    token = get_tenant_token()
    if token:
        send_invite_to_all_group(token)

